class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      onGenerateRoute: (settings) => RouteGenerator.generateRoute(settings),
      initialRoute: '/',
    );
  }
}

class RouteGenerator {
  static Map<String, Function> routes = {
    '/': (_) => MyHomePage(),
    '/profile/:id': (settings) => ProfilePage(id: settings.arguments),
    '/payment/confirm': (_) => PaymentConfirmPage(),
  };

  static Route generateRoute(RouteSettings settings) {
    final routeName = settings.name;
    if (routeName == null || !routes.containsKey(routeName)) {
      return MaterialPageRoute(builder: (context) => MyHomePage());
    }

    final arguments = settings.arguments;
    if (arguments is String && routeName.startsWith('/profile/')) {
      final id = arguments.split('/').last;
      return MaterialPageRoute(builder: (context) => ProfilePage(id: int.parse(id)));
    }

    return MaterialPageRoute(builder: (context) => routes[routeName](settings));
  }
}

class MyHomePage extends StatelessWidget {
